import{_ as a,o as n,c as i,af as o}from"./chunks/framework.BSym9njW.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"01-deploy/minicpm-o/index.md","filePath":"en/01-deploy/minicpm-o/index.md","lastUpdated":1782372845000}'),l={name:"01-deploy/minicpm-o/index.md"};function t(r,e,s,d,p,m){return n(),i("div",null,[...e[0]||(e[0]=[o(`<div align="center"><h1>MiniCPM-o 4.5 Deployment</h1><strong>🎙️ Running a Full-Omni Model on AMD GPU</strong></div><div align="center"><p><em>Audio · Vision · TTS · Full-Duplex · ROCm 7+ · llama.cpp-omni</em></p><p><a href="/hello-rocm/">Home</a> · <a href="/hello-rocm/zh/01-deploy/minicpm-o/">中文</a> · <a href="/hello-rocm/01-deploy/">Deploy Overview</a></p></div><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>  <strong>MiniCPM-o 4.5</strong> is an end-side omni-modal model from OpenBMB that combines <strong>text, voice input (audio encoder), image understanding (vision encoder), and voice output (TTS)</strong> into a single model. Its Omni full-duplex mode enables real-time, phone-call-like conversations — all running on AMD ROCm without an NVIDIA GPU.</p><p>  This module is based on OpenBMB&#39;s official <a href="https://github.com/tc-mb/llama.cpp-omni" target="_blank" rel="noreferrer">llama.cpp-omni</a> inference engine and <a href="https://github.com/OpenBMB/MiniCPM-o-Demo" target="_blank" rel="noreferrer"><code>OpenBMB/MiniCPM-o-Demo</code></a> (<code>Comni</code> branch), verified on <strong>AMD Ryzen AI MAX+ 395 (gfx1151 / Strix Halo APU)</strong> and applicable to other ROCm-supported AMD GPUs.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span>01-Deploy/minicpm-o/</span></span>
<span class="line"><span>├── minicpm-o-model.md               # MiniCPM-o 4.5 model introduction</span></span>
<span class="line"><span>├── llamacpp-omni-rocm7-deploy.md    # llama.cpp-omni CLI deployment</span></span>
<span class="line"><span>└── webdemo-rocm7-deploy.md          # MiniCPM-o Web Demo full-duplex deployment</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><hr><h2 id="tutorial-list" tabindex="-1">Tutorial List <a class="header-anchor" href="#tutorial-list" aria-label="Permalink to &quot;Tutorial List&quot;">​</a></h2><h3 id="minicpm-o-4-5-model-introduction" tabindex="-1">MiniCPM-o 4.5 Model Introduction <a class="header-anchor" href="#minicpm-o-4-5-model-introduction" aria-label="Permalink to &quot;MiniCPM-o 4.5 Model Introduction&quot;">​</a></h3><p>  Understand the omni-modal architecture of MiniCPM-o 4.5 — audio input, visual encoding, TTS synthesis, and full-duplex design. After reading, you&#39;ll know exactly which GGUF sub-model files are required and the VRAM requirements for different GPUs.</p><ul><li><strong>Audience</strong>: Readers who want to understand the model before deploying</li><li><strong>Difficulty</strong>: ⭐</li><li><strong>Estimated time</strong>: 15 minutes</li></ul><p>📖 <a href="./minicpm-o-model">Read MiniCPM-o 4.5 Model Introduction</a></p><hr><h3 id="llama-cpp-omni-cli-deployment" tabindex="-1">llama.cpp-omni CLI Deployment <a class="header-anchor" href="#llama-cpp-omni-cli-deployment" aria-label="Permalink to &quot;llama.cpp-omni CLI Deployment&quot;">​</a></h3><p>  Build and run MiniCPM-o 4.5 on AMD GPU using OpenBMB&#39;s official llama.cpp-omni inference engine. This tutorial covers HIP compilation, GGUF model download, audio input testing, and TTS voice output — letting you run full omni-modal inference from the command line.</p><ul><li><strong>Audience</strong>: Developers who want to verify inference capabilities or prepare a backend for the Web Demo</li><li><strong>Difficulty</strong>: ⭐⭐⭐</li><li><strong>Estimated time</strong>: 2 hours (including model download)</li></ul><p>📖 <a href="./llamacpp-omni-rocm7-deploy">Start llama.cpp-omni Deployment Tutorial</a></p><hr><h3 id="minicpm-o-web-demo-full-duplex-deployment" tabindex="-1">MiniCPM-o Web Demo Full-Duplex Deployment <a class="header-anchor" href="#minicpm-o-web-demo-full-duplex-deployment" aria-label="Permalink to &quot;MiniCPM-o Web Demo Full-Duplex Deployment&quot;">​</a></h3><p>  Deploy the complete Web Demo using <code>OpenBMB/MiniCPM-o-Demo</code> (<code>Comni</code> branch) on AMD GPU. Supports <strong>Turn-based / Half-Duplex / Omni full-duplex / Audio full-duplex</strong> — experience real-time voice and video conversation with the model directly in your browser. Prerequisite: llama.cpp-omni must already be compiled.</p><ul><li><strong>Audience</strong>: Developers who want to build a full interactive demonstration</li><li><strong>Difficulty</strong>: ⭐⭐⭐</li><li><strong>Estimated time</strong>: 1 hour (with inference backend already ready)</li></ul><p>📖 <a href="./webdemo-rocm7-deploy">Start Web Demo Full-Duplex Deployment</a></p><hr><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><h3 id="hardware" tabindex="-1">Hardware <a class="header-anchor" href="#hardware" aria-label="Permalink to &quot;Hardware&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Scenario</th><th>Minimum</th><th>Recommended</th></tr></thead><tbody><tr><td>Text inference (LLM only)</td><td>8 GB VRAM</td><td>—</td></tr><tr><td>Voice input (audio encoder)</td><td>12 GB VRAM</td><td>—</td></tr><tr><td>Full omni (LLM + vision + audio + TTS)</td><td><strong>16 GB VRAM</strong></td><td>64 GB unified memory (Strix Halo APU)</td></tr></tbody></table><blockquote><p>AMD Ryzen AI MAX+ 395 / 890M with unified memory architecture is ideal for MiniCPM-o — 64 GB unified memory can fully load all GGUF sub-models (~8.3 GB) into the GPU.</p></blockquote><h3 id="software" tabindex="-1">Software <a class="header-anchor" href="#software" aria-label="Permalink to &quot;Software&quot;">​</a></h3><ul><li>OS: Linux (Ubuntu 22.04 / 24.04)</li><li>ROCm 7.10.0 or later (system installation)</li><li>CMake 3.21+, GCC / Clang (for HIP compilation)</li><li>Python 3.10+ (Web Demo dependency)</li></ul><h3 id="test-environment-for-this-tutorial" tabindex="-1">Test Environment for This Tutorial <a class="header-anchor" href="#test-environment-for-this-tutorial" aria-label="Permalink to &quot;Test Environment for This Tutorial&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span>Hardware:  AMD Ryzen AI MAX+ PRO 395 / Radeon™ 890M (Strix Halo)</span></span>
<span class="line"><span>GPU arch:  gfx1151</span></span>
<span class="line"><span>Memory:    64 GB unified (all usable as VRAM)</span></span>
<span class="line"><span>ROCm:      7.12.0 (system) + TheRock 7.12.0a alpha (Tensile fix)</span></span>
<span class="line"><span>OS:        Ubuntu 24.04</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><hr><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><details><summary>Q: How is MiniCPM-o different from a regular LLM, and why can&#39;t I use vLLM / Ollama?</summary><p>MiniCPM-o 4.5 includes independent sub-modules — an audio encoder, a vision encoder, and a TTS token2wav pipeline — that mainstream inference frameworks don&#39;t natively support yet. llama.cpp-omni is a specialized inference engine fork that can load and schedule all these sub-models concurrently.</p></details><details><summary>Q: Does gfx1151 (Strix Halo) require special handling?</summary><p>Yes. gfx1151 was introduced in late 2025. The system <code>/opt/rocm</code> rocBLAS Tensile library doesn&#39;t include complete GEMM kernels for gfx1151, causing a crash at runtime (<code>hipErrorInvalidImage</code>). The fix is to install the TheRock 7.12.0a alpha SDK and point the runtime at its rocBLAS library directory — see the <a href="./llamacpp-omni-rocm7-deploy">llama.cpp-omni tutorial</a> for details.</p><p>Other AMD GPUs (gfx1100 / RX 7900 XTX, gfx1150 / RX 9070 XT, etc.) are not affected.</p></details><details><summary>Q: How do I find my AMD GPU architecture (gfx number)?</summary><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#795E26;--shiki-dark:#DCDCAA;">rocminfo</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;"> | </span><span style="--shiki-light:#795E26;--shiki-dark:#DCDCAA;">grep</span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;"> -i</span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;"> &quot;gfx&quot;</span></span>
<span class="line"><span style="--shiki-light:#008000;--shiki-dark:#6A9955;"># or</span></span>
<span class="line"><span style="--shiki-light:#795E26;--shiki-dark:#DCDCAA;">amd-smi</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div></details><hr><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li><a href="https://github.com/OpenBMB/MiniCPM-o" target="_blank" rel="noreferrer">MiniCPM-o Official Repository (OpenBMB)</a></li><li><a href="https://github.com/tc-mb/llama.cpp-omni" target="_blank" rel="noreferrer">llama.cpp-omni</a></li><li><a href="https://github.com/OpenBMB/MiniCPM-o-Demo" target="_blank" rel="noreferrer">MiniCPM-o-Demo Official Repository</a></li><li><a href="https://www.modelscope.cn/models/OpenBMB/MiniCPM-o-4_5-gguf" target="_blank" rel="noreferrer">MiniCPM-o-4_5-gguf (ModelScope)</a></li><li><a href="https://rocm.docs.amd.com/" target="_blank" rel="noreferrer">ROCm Official Documentation</a></li><li><a href="https://rocm.nightlies.amd.com/v2/gfx1151/" target="_blank" rel="noreferrer">TheRock Nightly SDK (gfx1151 fix)</a></li></ul><hr><div align="center"><p><strong>Contributions welcome!</strong> 🎉</p><p><a href="https://github.com/datawhalechina/hello-rocm/issues" target="_blank" rel="noreferrer">Submit Issue</a> | <a href="https://github.com/datawhalechina/hello-rocm/pulls" target="_blank" rel="noreferrer">Submit PR</a></p></div>`,41)])])}const h=a(l,[["render",t]]);export{u as __pageData,h as default};
